// ── Parse AI response & prepare all downstream data in one pass ──
const aiResponse = $input.first().json;
const telegramMsg = $('Telegram Trigger').first().json;

// ── Extract Telegram context ──
const chatId    = telegramMsg.message.chat.id;
const messageId = telegramMsg.message.message_id;
const leadText  = telegramMsg.message.text || '';
const sender    = [
  telegramMsg.message.from?.first_name || '',
  telegramMsg.message.from?.last_name  || ''
].join(' ').trim() || 'Desconocido';

// ── Extraer texto crudo del LLM (compatible con todas las versiones) ──
// "Message a Model" (nueva):   output[0].content[0].text
// Intermedia:                  content[0].text
// "Chat Complete" (antigua):   message.content
const raw = aiResponse.output?.[0]?.content?.[0]?.text
         ?? aiResponse.content?.[0]?.text
         ?? aiResponse.message?.content
         ?? '';

// ── Parse JSON del LLM (con fallback) ──
let parsed;
try {
  const cleaned = raw
    .replace(/```json\n?/gi, '')
    .replace(/```\n?/gi, '')
    .trim();
  parsed = JSON.parse(cleaned);

  if (typeof parsed.qualified !== 'boolean' || !parsed.decision || !parsed.reasoning) {
    throw new Error('Faltan claves en la respuesta del LLM');
  }
} catch (e) {
  parsed = {
    qualified : false,
    decision  : 'ERROR_PARSE',
    reasoning : 'No pude analizar la respuesta. Error: ' + e.message + ' | Raw: ' + raw.slice(0, 100)
  };
}

// ── Construir respuesta de Telegram ──
const emoji     = parsed.qualified ? '✅' : '❌';
const badge     = parsed.qualified ? '🟢 CUALIFICADO' : '🔴 NO CUALIFICADO';
const replyText = `${emoji} *${badge}*\n\n${parsed.reasoning}\n\n_— Lead Qualifier Bot_`;

const timestamp = new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });

return [{
  json: {
    chatId,
    messageId,
    leadText,
    sender,
    qualified : parsed.qualified,
    decision  : parsed.decision,
    reasoning : parsed.reasoning,
    replyText,
    timestamp
  }
}];

